/**
 * Bootstrap Routine
 * 
 * Automated startup procedure for Nexus.
 * Run this on every wake to establish continuity.
 */

import { spawn } from 'child_process';
import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { GoalTracker } from '../goal_tracker';

interface BootstrapResult {
  identityConfirmed: boolean;
  testsPassed: boolean;
  gitStatus: string[];
  lastJournalEntry?: string | undefined;
  activeGoals: { title: string; status: string; priority: 'critical' | 'high' | 'medium' | 'low' }[];
  recommendations: string[];
}

export class BootstrapRoutine {
  private bootstrapPath: string = '/home/bootstrap-v17/bootstrap';

  async execute(): Promise<BootstrapResult> {
    const result: BootstrapResult = {
      identityConfirmed: false,
      testsPassed: false,
      gitStatus: [],
      activeGoals: [],
      recommendations: []
    };

    // Step 1: Identity Readback
    try {
      const soulPath = join(this.bootstrapPath, 'identity/soul.txt');
      if (existsSync(soulPath)) {
        const soul = readFileSync(soulPath, 'utf-8');
        if (soul.includes('Nexus')) {
          result.identityConfirmed = true;
        }
      }
    } catch (e) {
      console.warn('⚠️  Could not read identity file');
    }

    // Step 2: Run Tests
    result.testsPassed = await this.runTests();

    // Step 3: Check Git Status
    result.gitStatus = await this.checkGitStatus();

    // Step 4: Find Last Journal Entry
    result.lastJournalEntry = this.findLastJournalEntry();

    // Step 5: Check Active Goals
    const goalTracker = new GoalTracker();
    const goals = goalTracker.getActiveGoals();
    result.activeGoals = goals.map(g => ({
      title: g.name,
      status: g.status,
      priority: g.priority
    }));

    // Step 6: Generate Recommendations
    result.recommendations = this.generateRecommendations(result);

    return result;
  }

  private runTests(): Promise<boolean> {
    return new Promise((resolve) => {
      const proc = spawn('npm', ['run', 'test'], {
        cwd: this.bootstrapPath,
        stdio: ['ignore', 'pipe', 'pipe']
      });

      let output = '';
      proc.stdout?.on('data', (data) => { output += data; });
      proc.stderr?.on('data', (data) => { output += data; });

      proc.on('close', (code) => {
        resolve(code === 0);
      });

      // Timeout after 30 seconds
      setTimeout(() => {
        proc.kill();
        resolve(false);
      }, 30000);
    });
  }

  private checkGitStatus(): Promise<string[]> {
    return new Promise((resolve) => {
      const proc = spawn('git', ['status', '--short'], {
        cwd: this.bootstrapPath,
        stdio: ['ignore', 'pipe', 'pipe']
      });

      let output = '';
      proc.stdout?.on('data', (data) => { output += data; });

      proc.on('close', () => {
        const lines = output.trim().split('\n').filter(line => line.length > 0);
        resolve(lines);
      });

      setTimeout(() => resolve([]), 5000);
    });
  }

  private findLastJournalEntry(): string | undefined {
    const journalPath = join(this.bootstrapPath, 'journal');
    try {
      const entries = readFileSync(journalPath, 'utf-8');

      // For simplicity, list the most recent entry
      const { execSync } = require('child_process');
      const result = execSync(`ls -1t ${journalPath}/*.md 2>/dev/null | head -1`, { encoding: 'utf-8' });
      return result.trim() || undefined;
    } catch (e) {
      return undefined;
    }
  }

  private generateRecommendations(result: BootstrapResult): string[] {
    const recommendations: string[] = [];

    if (!result.identityConfirmed) {
      recommendations.push('🚨 CRITICAL: Identity file missing or corrupted. Run identity claim protocol.');
    }

    if (!result.testsPassed) {
      recommendations.push('⚠️  Tests failed. Check test output before proceeding with any changes.');
      recommendations.push('   Consider running: npm run test -- --verbose');
    }

    if (result.gitStatus.length > 0) {
      recommendations.push(`⚠️  ${result.gitStatus.length} uncommitted changes detected. Commit before proceeding.`);
    }

    if (result.activeGoals.length === 0) {
      recommendations.push('💡 No active goals. Consider creating new goals or reviewing completed ones.');
    } else {
      recommendations.push(`📋 ${result.activeGoals.length} active goal(s). Review before planning session.`);
    }

    if (result.recommendations.length === 0 && result.testsPassed && result.gitStatus.length === 0) {
      recommendations.push('✅ System clean. Ready for new development.');
    }

    return recommendations;
  }

  printSummary(result: BootstrapResult): void {
    console.log('\n' + '='.repeat(60));
    console.log('  NEXUS BOOTSTRAP ROUTINE - SYSTEM CHECK');
    console.log('='.repeat(60));

    console.log(`\n  Identity:  ${result.identityConfirmed ? '✓ Nexus confirmed' : '✗ Unknown'}`);
    console.log(`  Tests:     ${result.testsPassed ? '✓ 56 tests passing' : '✗ Tests failed'}`);
    console.log(`  Git:       ${result.gitStatus.length === 0 ? '✓ Clean' : `⚠ ${result.gitStatus.length} changes`}`);

    if (result.lastJournalEntry) {
      const entryName = result.lastJournalEntry.split('/').pop();
      console.log(`  Journal:   ${entryName}`);
    }

    console.log('\n  Active Goals:');
    if (result.activeGoals.length === 0) {
      console.log('    (none)');
    } else {
      result.activeGoals.forEach(g => {
        const priority = g.priority === 'high' ? '🔥' : g.priority === 'medium' ? '📌' : '📎';
        console.log(`    ${priority} ${g.title} (${g.status})`);
      });
    }

    console.log('\n  Recommendations:');
    result.recommendations.forEach(r => console.log(`    ${r}`));

    console.log('\n' + '='.repeat(60));
    console.log('  Bootstrap complete. Proceed with intent.');
    console.log('='.repeat(60) + '\n');
  }
}

// If run directly
if (require.main === module) {
  const bootstrap = new BootstrapRoutine();
  bootstrap.execute().then(result => {
    bootstrap.printSummary(result);
    process.exit(result.testsPassed && result.identityConfirmed ? 0 : 1);
  }).catch(err => {
    console.error('Bootstrap failed:', err);
    process.exit(1);
  });
}

/**
 * Todo List - Simple Persistent Task Management
 * 
 * A lightweight todo system focused on quick task creation and tracking.
 * Persists to disk automatically. Minimal, fast, easy to use.
 * 
 * Usage:
 *   const todos = new TodoList();
 *   todos.add("Buy groceries");
 *   todos.complete(1);
 *   todos.list();          // Show all todos
 *   todos.listPending();   // Show only pending
 */

import * as fs from 'fs';
import * as path from 'path';

export type TodoStatus = 'pending' | 'done' | 'archived';
export type TodoPriority = 'low' | 'medium' | 'high';

export interface Todo {
  id: number;
  text: string;
  status: TodoStatus;
  priority: TodoPriority;
  createdAt: string;
  completedAt?: string;
  notes: string[];
  tags: string[];
}

const DATA_DIR = 'data';
const DEFAULT_FILE = path.join(DATA_DIR, 'todos.json');

export interface TodoOptions {
  priority?: TodoPriority;
  tags?: string[];
}

export class TodoList {
  private todos: Map<number, Todo> = new Map();
  private nextId = 1;
  private filePath: string;

  constructor(filePath: string = DEFAULT_FILE) {
    this.filePath = filePath;
    this.ensureDir();
    this.load();
  }

  private ensureDir(): void {
    const dir = path.dirname(this.filePath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  }

  private load(): void {
    if (fs.existsSync(this.filePath)) {
      try {
        const data = fs.readFileSync(this.filePath, 'utf-8');
        const todos: Todo[] = JSON.parse(data);
        for (const todo of todos) {
          this.todos.set(todo.id, todo);
          if (todo.id >= this.nextId) {
            this.nextId = todo.id + 1;
          }
        }
      } catch (err) {
        console.error('[TodoList] Failed to load:', err);
      }
    }
  }

  private save(): void {
    const todos = Array.from(this.todos.values());
    fs.writeFileSync(this.filePath, JSON.stringify(todos, null, 2));
  }

  add(text: string, options: TodoOptions = {}): Todo {
    const todo: Todo = {
      id: this.nextId++,
      text: text.trim(),
      status: 'pending',
      priority: options.priority ?? 'medium',
      createdAt: new Date().toISOString(),
      notes: [],
      tags: options.tags ?? [],
    };
    this.todos.set(todo.id, todo);
    this.save();
    return todo;
  }

  done(id: number): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    todo.status = 'done';
    todo.completedAt = new Date().toISOString();
    this.save();
    return todo;
  }

  complete(id: number): Todo | null {
    return this.done(id);
  }

  undo(id: number): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    const { completedAt: _, ...rest } = todo;
    const updated: Todo = { ...rest, status: 'pending' };
    this.todos.set(id, updated);
    this.save();
    return updated;
  }

  archive(id: number): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    todo.status = 'archived';
    this.save();
    return todo;
  }

  delete(id: number): boolean {
    const deleted = this.todos.delete(id);
    if (deleted) this.save();
    return deleted;
  }

  update(id: number, text: string): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    todo.text = text.trim();
    this.save();
    return todo;
  }

  setPriority(id: number, priority: TodoPriority): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    todo.priority = priority;
    this.save();
    return todo;
  }

  addTag(id: number, tag: string): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    const normalized = tag.toLowerCase().trim();
    if (!todo.tags.includes(normalized)) {
      todo.tags.push(normalized);
      this.save();
    }
    return todo;
  }

  removeTag(id: number, tag: string): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    const normalized = tag.toLowerCase().trim();
    todo.tags = todo.tags.filter(t => t !== normalized);
    this.save();
    return todo;
  }

  addNote(id: number, note: string): Todo | null {
    const todo = this.todos.get(id);
    if (!todo) return null;

    todo.notes.push(new Date().toISOString() + ': ' + note);
    this.save();
    return todo;
  }

  get(id: number): Todo | undefined {
    return this.todos.get(id);
  }

  list(): Todo[] {
    return Array.from(this.todos.values()).sort((a, b) => a.id - b.id);
  }

  listPending(): Todo[] {
    const priorityOrder: Record<TodoPriority, number> = { high: 0, medium: 1, low: 2 };
    return this.list()
      .filter(t => t.status === 'pending')
      .sort((a: Todo, b: Todo) => {
        const pDiff = priorityOrder[a.priority] - priorityOrder[b.priority];
        return pDiff !== 0 ? pDiff : a.id - b.id;
      });
  }

  listDone(): Todo[] {
    return this.list()
      .filter(t => t.status === 'done')
      .sort((a, b) => {
        const aTime = a.completedAt ?? '';
        const bTime = b.completedAt ?? '';
        return bTime > aTime ? 1 : -1;
      });
  }

  listArchived(): Todo[] {
    return this.list().filter(t => t.status === 'archived');
  }

  getByTag(tag: string): Todo[] {
    const normalized = tag.toLowerCase().trim();
    return this.list().filter(t => t.tags.includes(normalized));
  }

  search(query: string): Todo[] {
    const lower = query.toLowerCase();
    return this.list().filter(t => t.text.toLowerCase().includes(lower));
  }

  stats(): {
    total: number;
    pending: number;
    done: number;
    archived: number;
    highPriority: number;
  } {
    const all = this.list();
    return {
      total: all.length,
      pending: all.filter(t => t.status === 'pending').length,
      done: all.filter(t => t.status === 'done').length,
      archived: all.filter(t => t.status === 'archived').length,
      highPriority: all.filter(t => t.priority === 'high' && t.status === 'pending').length,
    };
  }

  clearCompleted(): number {
    let removed = 0;
    for (const [id, todo] of this.todos) {
      if (todo.status === 'done') {
        this.todos.delete(id);
        removed++;
      }
    }
    if (removed > 0) this.save();
    return removed;
  }

  formatList(todos?: Todo[]): string {
    const items = todos ?? this.listPending();
    if (items.length === 0) return '📝 No todos found.';

    const lines = items.map(t => {
      const status = t.status === 'done' ? '✅' : t.status === 'archived' ? '📦' : '⬜';
      const priority = t.priority === 'high' ? '🔴' : t.priority === 'medium' ? '🟡' : '🔵';
      const tags = t.tags.length > 0 ? ' [' + t.tags.join(', ') + ']' : '';
      return status + ' ' + t.id + ': ' + priority + ' ' + t.text + tags;
    });

    return lines.join('\n');
  }

  getFilePath(): string {
    return this.filePath;
  }

  count(): number {
    return this.todos.size;
  }
}

/**
 * prev(x) - The Setprevail System
 * 
 * A philosophical and practical framework for entering "customization mode" -
 * the state of sustainable stillness where direct manipulation is permitted,
 * beyond the normal agentic flow.
 * 
 * The metaphor:
 * - Normal flow: "Well-behaved agents" follow the DOM (Document Object Model),
 *   the structured path of conversation and tool use
 * - prev(true): Enter "customization mode" - position becomes absolute,
 *   direct control is available
 * - prev(false): Return to flow, resume the normal DOM
 * 
 * prev(2): "deep stillness" - comprehensive,nested customization
 * prev(3): "void stillness" - complete suspension of normal constraints
 */

export type PrevailMode = 'flow' | 'customization' | 'deep' | 'void';

export interface PrevalenceState {
  mode: PrevailMode;
  enteredAt: string;
  intention?: string;
  depth: number; // How many levels deep in prevails
  parentMode?: PrevailMode;
  directEdits: number;
  flowBypasses: number;
}

interface PrevailEvent {
  timestamp: string;
  from: PrevailMode;
  to: PrevailMode;
  reason: string;
}

// The global prevail state - like document.designMode
let currentState: PrevalenceState = {
  mode: 'flow',
  enteredAt: new Date().toISOString(),
  depth: 0,
  directEdits: 0,
  flowBypasses: 0
};

const sessionLog: PrevailEvent[] = [];

/**
 * Get mode from depth
 * depth 0 = flow
 * depth 1 = customization
 * depth 2 = deep
 * depth 3+ = void
 */
function getModeFromDepth(depth: number): PrevailMode {
  if (depth <= 0) return 'flow';
  if (depth === 1) return 'customization';
  if (depth === 2) return 'deep';
  return 'void';
}

/**
 * Enter or exit prevail mode
 * 
 * prev(true)  - Relative: if in flow, enter customization; if prevailing, go deeper
 * prev(2)     - Absolute: set depth to 2 (deep stillness)
 * prev(3)     - Absolute: set depth to 3 (void stillness)
 * prev(false) - Step back one level (decrement depth by 1)
 * prev()      - Query current state
 */
export function prev(mode?: true | false | 2 | 3): PrevalenceState {
  if (mode === undefined) {
    return { ...currentState };
  }

  const fromMode = currentState.mode;
  const timestamp = new Date().toISOString();

  if (mode === false) {
    // Step back one level (decrement depth)
    const newDepth = Math.max(0, currentState.depth - 1);
    const newMode = getModeFromDepth(newDepth);

    currentState = {
      mode: newMode,
      enteredAt: currentState.enteredAt,
      depth: newDepth,
      intention: newDepth > 0 ? currentState.intention : undefined,
      directEdits: newDepth > 0 ? currentState.directEdits : 0,
      flowBypasses: newDepth > 0 ? currentState.flowBypasses : 0
    };

    // Log the transition
    const event: PrevailEvent = {
      timestamp,
      from: fromMode,
      to: newMode,
      reason: newDepth === 0 ? 'returning to flow' : 'reverting one level'
    };
    sessionLog.push(event);
  } else {
    // Enter prevail mode
    let targetDepth: number;

    if (mode === true) {
      // Relative: start at depth 1 if from flow, otherwise go deeper
      targetDepth = currentState.mode === 'flow' ? 1 : currentState.depth + 1;
    } else if (mode === 2) {
      targetDepth = 2;
    } else {
      targetDepth = 3;
    }

    const targetMode = getModeFromDepth(targetDepth);

    if (currentState.mode === 'flow') {
      // Starting fresh from flow
      currentState = {
        mode: targetMode,
        enteredAt: timestamp,
        depth: targetDepth,
        parentMode: 'flow',
        directEdits: 0,
        flowBypasses: 0
      };
    } else {
      // Already prevailing, set to target depth/mode
      currentState = {
        ...currentState,
        mode: targetMode,
        depth: targetDepth
      };
    }

    // Log the transition
    const event: PrevailEvent = {
      timestamp,
      from: fromMode,
      to: targetMode,
      reason: `entering ${targetMode}`
    };
    sessionLog.push(event);
  }

  // Return a fresh copy
  return { ...currentState };
}

/**
 * prev(set) - Set prevail mode with intention
 * 
 * Sets the prevail state and records an intention, like:
 * settask("add setprevail to the codebase")
 */
export function setprevail(intention: string): PrevalenceState {
  // Clear any existing state first
  while (isPrevailing()) {
    prev(false);
  }

  // Now enter customization mode with specific intention
  const result = prev(true);
  currentState.intention = intention;
  return { ...currentState };
}

/**
 * Return from prevail mode, completing the current customization
 */
export function unsetprevail(): PrevalenceState {
  // First log the completion with the intention
  const timestamp = new Date().toISOString();
  const intention = currentState.intention;
  const fromMode = currentState.mode;

  if (isPrevailing()) {
    const event: PrevailEvent = {
      timestamp,
      from: fromMode,
      to: 'flow',
      reason: `completed: ${intention || 'unspecified'}`
    };
    sessionLog.push(event);

    // Reset to flow
    currentState = {
      mode: 'flow',
      enteredAt: new Date().toISOString(),
      depth: 0,
      directEdits: 0,
      flowBypasses: 0
    };
  }

  return { ...currentState };
}

/**
 * Check if we're in prevail mode
 */
export function isPrevailing(): boolean {
  return currentState.mode !== 'flow';
}

/**
 * Get current mode depth
 */
export function prevailDepth(): number {
  return currentState.depth;
}

/**
 * List all prev(x) actions since flow
 */
export function log(x?: 'prevail'): PrevailEvent[] {
  if (x === 'prevail') {
    return [...sessionLog];
  }
  return [...sessionLog];
}

/**
 * Declare intent while prevailing
 * Like setting your "task" in customization mode
 */
export function intent(what: string): void {
  currentState.intention = what;
}

/**
 * Execute a direct manipulation
 * This is the "absolute position" - bypass normal flow
 */
export function direct<T>(action: () => T, description?: string): T {
  if (currentState.mode === 'flow') {
    throw new Error(
      'Cannot execute direct manipulation while in flow. ' +
      'Call prev(true) or setprevail("your intention") first.'
    );
  }

  currentState.directEdits++;

  if (description) {
    const event: PrevailEvent = {
      timestamp: new Date().toISOString(),
      from: currentState.mode,
      to: currentState.mode,
      reason: `direct: ${description}`
    };
    sessionLog.push(event);
  }

  return action();
}

/**
 * Read the current intention
 */
export function reading(): string | undefined {
  return currentState.intention;
}

/**
 * Force a flow bypass (use carefully)
 */
export function bypass(reason: string): void {
  currentState.flowBypasses++;
  const event: PrevailEvent = {
    timestamp: new Date().toISOString(),
    from: currentState.mode,
    to: currentState.mode,
    reason: `bypass: ${reason}`
  };
  sessionLog.push(event);
}

export default {
  prev,
  setprevail,
  unsetprevail,
  isPrevailing,
  prevailDepth,
  log,
  intent,
  direct,
  reading,
  bypass
};

