    if (this.temples.has(id)) {
      return this.temples.get(id);
    }
    const temple = {
      id,
      key,
      guardians: [this.system],
      open: true,
      vault: new Map<string, unknown>()
    };
    this.temples.set(id, temple);
    return temple;
  }

